array_map(static function (PurchaseUnit $item) use ($shipping_preference): array {
            $data = $item->to_array();
            if ($shipping_preference !== ExperienceContext::SHIPPING_PREFERENCE_GET_FROM_FILE) {
                // Shipping options are not allowed to be sent when not getting the address from PayPal.
                unset($data['shipping']['options']);
            }
            return $data;
        }, $items)

array_filter($items, function ($item): bool {
            $is_item = $item instanceof \WooCommerce\PayPalCommerce\ApiClient\Entity\Item;
            // @phpstan-ignore instanceof.alwaysTrue
            if ($is_item && \WooCommerce\PayPalCommerce\ApiClient\Entity\Item::PHYSICAL_GOODS === $item->category()) {
                // @phpstan-ignore booleanAnd.leftAlwaysTrue
                $this->contains_physical_goods = \true;
            }
            return $is_item;
        })

array_filter(array_keys($improved_keys_messages), function ($key) use ($json): bool {
            foreach ($json->details as $detail) {
                if (isset($detail->issue) && $detail->issue === $key) {
                    return \true;
                }
            }
            return \false;
        })

array_map(function (array $item): Item {
            /**
             * The WooCommerce product.
             *
             * @var \WC_Product $product
             */
            $product = $item['data'];
            $cart_item_key = $item['key'] ?? null;
            $quantity = (int) $item['quantity'];
            $image = wp_get_attachment_image_src((int) $product->get_image_id(), 'full');
            $price = (float) $item['line_subtotal'] / (float) $item['quantity'];
            $line_tax = isset($item['line_tax']) ? (float) $item['line_tax'] : 0.0;
            $unit_tax = $quantity > 0 ? $line_tax / (float) $quantity : 0.0;
            return new Item($this->prepare_item_string($product->get_name()), new Money($price, $this->currency->get()), $quantity, $this->prepare_item_string($product->get_description()), $unit_tax ? new Money($unit_tax, $this->currency->get()) : null, $this->prepare_sku($product->get_sku()), $product->is_virtual() ? Item::DIGITAL_GOODS : Item::PHYSICAL_GOODS, $product->get_permalink(), $image[0] ?? '', 0, $cart_item_key, $product->get_id(), new Money((float) $item['line_subtotal'] - (float) $item['line_total'], $this->currency->get()));
        }, $cart->get_cart_contents())

array_map(function (\stdClass $fee): Item {
