array_filter($keys, static function ($key): bool {
            if (!is_array($key)) {
                return \false;
            }
            if (($key['kty'] ?? '') !== self::EXPECTED_KEY_TYPE) {
                return \false;
            }
            if (isset($key['alg']) && $key['alg'] !== self::EXPECTED_ALGORITHM) {
                return \false;
            }
            return \true;
        })

