array_map(static function ($link) use ($linkType, $version, $prettyVersion, $vp, $packages) {
            if ('self.version' === $link->getPrettyConstraint()) {
                if (isset($packages[$link->getSource()])) {
                    /** @var Link $package */
                    $package = $packages[$link->getSource()];
                    return new Link($link->getSource(), $link->getTarget(), $vp->parseConstraints($package->getConstraint()->getPrettyString()), $linkType['description'], $package->getPrettyConstraint());
                }
                return new Link($link->getSource(), $link->getTarget(), $vp->parseConstraints($version), $linkType['description'], $prettyVersion);
            }
            return $link;
        }, $links)

array_map(static function ($files, $pattern) use ($required) {
            if ($required && !$files) {
                throw new \Wikimedia\Composer\Merge\V2\MissingFileException("merge-plugin: No files matched required '{$pattern}'");
            }
            return $files;
        }, array_map('glob', $patterns), $patterns)

